Create the Node backend context once in a server-only module and reuse it:

```ts
import { createJazzContext } from "jazz-tools/backend";
import { app } from "./schema";
import permissions from "./permissions";

export const jazz = createJazzContext({
  appId: process.env.JAZZ_APP_ID!,
  app,
  permissions,
  driver: { type: "persistent", dataPath: process.env.JAZZ_DATA_PATH ?? "./jazz-data" },
  serverUrl: process.env.JAZZ_SERVER_URL,
  backendSecret: process.env.BACKEND_SECRET,
  env: process.env.NODE_ENV === "production" ? "prod" : "dev",
  userBranch: "main",
});

process.once("SIGTERM", async () => {
  await jazz.shutdown();
  process.exit(0);
});
```

Install `jazz-napi` as a direct dependency for Node. Use a stable `dataPath` for persistent local state; `{ type: "memory" }` is ephemeral and only acceptable with an upstream `serverUrl`. Keep `BACKEND_SECRET` and `JAZZ_ADMIN_SECRET` server-only, never public-prefixed or bundled to the browser. Use `backendSecret` for server-connected backend/request-scoped handles, and explicitly wait for the needed durability tier before returning success from endpoints that promise persistence.

Use `null`, not `undefined`, when clearing an optional Jazz column. In an update payload, `undefined` means “leave this field unchanged.”

```ts
await db.update(app.todos, todoId, {
  projectId: null,
}).wait({ tier: "edge" });
```

If you do not need sync confirmation, you can omit `.wait(...)`; the local-first update still applies optimistically.

When query inputs are reactive, pass an accessor/function that builds the query from the current values.

Svelte:
```ts
import { QuerySubscription } from "jazz-tools/svelte";
import { app } from "./schema";

const todos = new QuerySubscription(() =>
  selectedProjectId
    ? app.todos.where({ projectId: selectedProjectId }).orderBy("title", "asc")
    : undefined,
);
```

Solid:
```ts
import { useAll } from "jazz-tools/solid";
import { app } from "./schema";

const todos = useAll(() => ({
  query: selectedProjectId()
    ? app.todos.where({ projectId: selectedProjectId() }).orderBy("title", "asc")
    : undefined,
}));
```

Building the query once captures the old input; the accessor shape lets the binding rerun when inputs change.

Use `db.batch(...)` for two optimistic UI writes that should appear together after the callback commits, then settle as one direct batch.

```ts
const result = db.batch((batch) => {
  batch.update(app.todos, firstId, { done: true });
  batch.update(app.todos, secondId, { done: true });
});
await result.wait({ tier: "edge" });
```

Use `db.transaction(...)` when the writes must remain staged until authority accepts them and then become globally visible together.

```ts
const result = await db.transaction(async (tx) => {
  tx.update(app.todos, firstId, { done: true });
  tx.update(app.todos, secondId, { done: true });
});
await result.wait({ tier: "global" });
```

Do not await individual writes inside the open batch or transaction; await the returned result.

Upload with an explicit edge tier on both the chunked file creation and the parent row creation:

```ts
const file = await db.createFileFromBlob(app, blob, { tier: "edge" });

const upload = await db
  .insert(app.uploads, {
    owner_id: session.user_id,
    label,
    fileId: file.id,
  })
  .wait({ tier: "edge" });
```

For streams, use `db.createFileFromStream(app, stream, { name, mimeType, tier: "edge" })`. On download, request the tier needed by the product and distinguish missing files from incomplete chunks:

```ts
try {
  const blob = await db.loadFileAsBlob(app, upload.fileId, { tier: "edge" });
  return blob;
} catch (err) {
  if (err instanceof FileNotFoundError) return { state: "missing" };
  if (err instanceof IncompleteFileDataError) {
    return { state: "incomplete", reason: err.reason };
  }
  throw err;
}
```

Treat `IncompleteFileDataError` as a retry/loading/corruption state, not as a successful download.

Delete while the parent relationship still exists, because file and part delete permissions are inherited through it. Load the parent first, then the file, then delete parts, then file, then parent:

```ts
const upload = await db.one(app.uploads.where({ id: uploadId }), { tier: "edge" });
if (!upload) return;

const file = await db.one(app.files.where({ id: upload.fileId }), { tier: "edge" });

if (file) {
  for (const partId of file.partIds) {
    db.delete(app.file_parts, partId);
  }
  db.delete(app.files, file.id);
}

db.delete(app.uploads, upload.id);
```

Do not delete the upload row first. That can remove the inherited authorization needed to delete the file row and its chunks, leaving orphaned data.

Use a real local in-memory Jazz server with two `createDb` clients, write the rows from Alice, wait for edge durability, then poll Bob until all rows arrive. Since row order is not the behavior under test, make the assertion deterministic by either adding an explicit `orderBy` to the query or normalizing by a stable key before comparing.

```ts
it("syncs multiple todos between clients without depending on result order", async () => {
  const server = await startLocalJazzServer({ inMemory: true });
  let alice: Db | undefined;
  let bob: Db | undefined;

  try {
    alice = await createDb({ appId: server.appId, serverUrl: server.url, adminSecret: server.adminSecret, driver: { type: "memory" } });
    bob = await createDb({ appId: server.appId, serverUrl: server.url, adminSecret: server.adminSecret, driver: { type: "memory" } });

    const input = ["gamma", "alpha", "beta"];

    await Promise.all(
      input.map((title) =>
        alice!.insert(app.todos, { title, done: false }).wait({ tier: "edge" }),
      ),
    );

    await vi.waitFor(async () => {
      const rows = await bob!.all(app.todos, { tier: "edge" });
      expect(rows.map((row) => row.title).sort()).toEqual(["alpha", "beta", "gamma"]);
    });
  } finally {
    await alice?.shutdown();
    await bob?.shutdown();
    await server.stop();
  }
});
```

If the app schema supports explicit ordering, prefer `app.todos.orderBy("title", "asc")` or the project’s existing query style and assert the ordered titles directly.

Use `createPolicyTestApp` so the test exercises public policy behavior without mocking enforcement. Assert denied reads as filtered results, and denied writes with `expectDenied`.

```ts
import { createPolicyTestApp, type PolicyTestApp } from "jazz-tools/testing";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import permissions from "../permissions";
import { app } from "../schema";

let testApp: PolicyTestApp;

beforeEach(async () => {
  testApp = await createPolicyTestApp(app, permissions, expect);
});

afterEach(async () => {
  await testApp.shutdown();
});

it("denies Bob read and write access to Alice's row", async () => {
  const alice = testApp.as({ user_id: "alice", claims: {}, authMode: "local-first" });
  const bob = testApp.as({ user_id: "bob", claims: {}, authMode: "local-first" });

  const created = alice.insert(app.todos, { title: "Alice private todo", done: false }).value;

  await expect(bob.all(app.todos.where({ id: created.id }))).resolves.toEqual([]);

  bob.expectDenied((db) =>
    db.update(app.todos, created.id, { title: "Bob should not update this" }),
  );

  alice.expectAllowed((db) =>
    db.update(app.todos, created.id, { title: "Alice can update this" }),
  );
});
```

If the policy also controls deletes or inserts into an owner-scoped table, add separate assertions for those operations instead of treating update denial as full write coverage.
